import tkinter as tkfrom tkinter import filedialog, ttk, messageboximport matplotlib.pyplot as pltfrom matplotlib.backends.backend_tkagg import FigureCanvasTkAgg, NavigationToolbar2Tkfrom matplotlib.widgets import MultiCursorimport numpy as npimport pandas as pdfrom data_processor import load_and_clean_data, calculate_derived_metrics, get_dyno_datafrom ui_mapping import MappingDialogclass LogAnalyzerApp:    def __init__(self, root):        self.root = root        self.root.title("PRO ECU Log Analyzer")        self.root.geometry("1400x850")                # Стилизация Matplotlib под темную тему        plt.style.use('dark_background')                self.df = None        self.mapping = None        self.x_values_np = None                self.setup_ui()        self.load_file()    def setup_ui(self):        # Панель управления (сверху)        toolbar_frame = tk.Frame(self.root, bg="#2d2d2d", pady=5)        toolbar_frame.pack(side="top", fill="x")                ttk.Button(toolbar_frame, text="Открыть другой лог", command=self.load_file).pack(side="left", padx=10)        ttk.Button(toolbar_frame, text="Dyno график (Мощность/Обороты)", command=self.show_dyno_graph).pack(side="left", padx=10)                # Главный контейнер        main_frame = tk.Frame(self.root)        main_frame.pack(side="top", fill="both", expand=True)                # Левая панель для вывода текста (ЭТО РЕШАЕТ ПРОБЛЕМУ ЛАГОВ)        self.info_panel = tk.Frame(main_frame, width=250, bg="#1e1e1e", padx=10, pady=10)        self.info_panel.pack(side="left", fill="y")        self.info_panel.pack_propagate(False)                tk.Label(self.info_panel, text="=== ДАННЫЕ ===", fg="lime", bg="#1e1e1e", font=("Consolas", 14, "bold")).pack(anchor="w", pady=(0, 10))                self.text_vars = {}        self.create_info_label("TIME", "Время:", "с")        self.create_info_label("RPM", "Обороты:", "RPM", color="cyan")        self.create_info_label("SPEED", "Скорость:", "км/ч", color="dodgerblue")        self.create_info_label("TPS", "Дроссель:", "%", color="red")        tk.Frame(self.info_panel, height=2, bg="#555").pack(fill="x", pady=5) # Разделитель        self.create_info_label("AFR", "Смесь (AFR):", "", color="violet")        self.create_info_label("INJ", "Впрыск:", "мс", color="lightblue")        self.create_info_label("GBC", "Наполнение:", "мг/ц", color="orange")        self.create_info_label("HP", "Мощность:", "л.с.", color="lime")        tk.Frame(self.info_panel, height=2, bg="#555").pack(fill="x", pady=5)        self.create_info_label("UOS", "УОЗ:", "°", color="yellow")        self.create_info_label("KNOCK", "Детонация:", "°", color="red")        self.create_info_label("IAC", "Шаги РХХ:", "", color="white")        tk.Frame(self.info_panel, height=2, bg="#555").pack(fill="x", pady=5)        self.create_info_label("T_WATER", "Темп. ОЖ:", "°C", color="magenta")        self.create_info_label("T_AIR", "Темп. Впуск:", "°C", color="pink")        # Контейнер для графика        self.plot_frame = tk.Frame(main_frame)        self.plot_frame.pack(side="right", fill="both", expand=True)    def create_info_label(self, key, title, unit, color="white"):        frame = tk.Frame(self.info_panel, bg="#1e1e1e")        frame.pack(fill="x", pady=2)        tk.Label(frame, text=title, fg="#aaaaaa", bg="#1e1e1e", font=("Consolas", 11)).pack(side="left")        var = tk.StringVar(value="-")        tk.Label(frame, textvariable=var, fg=color, bg="#1e1e1e", font=("Consolas", 12, "bold")).pack(side="right")        tk.Label(frame, text=f" {unit}", fg="#aaaaaa", bg="#1e1e1e", font=("Consolas", 10)).pack(side="right")        self.text_vars[key] = var    def load_file(self):        file_path = filedialog.askopenfilename(title="Выберите лог", filetypes=[("Log files", "*.csv *.txt"), ("All files", "*.*")])        if not file_path: return        try:            raw_df = load_and_clean_data(file_path)            dialog = MappingDialog(self.root, raw_df.columns)            self.root.wait_window(dialog.top)                        if not dialog.result: return            self.mapping = dialog.result            self.df = calculate_derived_metrics(raw_df, self.mapping)                        self.draw_plots()        except Exception as e:            messagebox.showerror("Ошибка", str(e))    def draw_plots(self):        for widget in self.plot_frame.winfo_children():            widget.destroy()        x_col = self.mapping.get('TIME')        x_axis = self.df[x_col] if x_col and x_col in self.df.columns else self.df.index        self.x_values_np = x_axis.to_numpy()        fig = plt.figure(figsize=(10, 8))        gs = fig.add_gridspec(6, 1, hspace=0.3)                # 1. Обороты и Дроссель        ax1 = fig.add_subplot(gs[0])        if 'RPM' in self.mapping: ax1.plot(x_axis, self.df[self.mapping['RPM']], color='cyan', label='Обороты')        if 'TPS' in self.mapping:            ax1_2 = ax1.twinx()            ax1_2.plot(x_axis, self.df[self.mapping['TPS']], color='red', label='Дроссель')            ax1_2.set_ylim(0, 105)        ax1.set_title("Обороты и Дроссель", pad=2, fontsize=10)        # 2. Воздух и Мощность        ax2 = fig.add_subplot(gs[1], sharex=ax1)        if 'GBC' in self.mapping: ax2.plot(x_axis, self.df[self.mapping['GBC']], color='orange')        ax2_2 = ax2.twinx()        ax2_2.plot(x_axis, self.df['Calculated_HP'], color='lime', linewidth=2)        ax2.set_title("Наполнение (Оранж) и Мощность (Зел)", pad=2, fontsize=10)        # 3. УОЗ и Детонация        ax3 = fig.add_subplot(gs[2], sharex=ax1)        if 'UOS' in self.mapping: ax3.plot(x_axis, self.df[self.mapping['UOS']], color='yellow')        if 'KNOCK' in self.mapping:            ax3_2 = ax3.twinx()            ax3_2.plot(x_axis, self.df[self.mapping['KNOCK']], color='red', drawstyle='steps-post')        ax3.set_title("УОЗ (Желт) и Детонация (Красн)", pad=2, fontsize=10)        # 4. Смесь (AFR) и Впрыск        ax4 = fig.add_subplot(gs[3], sharex=ax1)        if 'AFR' in self.mapping: ax4.plot(x_axis, self.df[self.mapping['AFR']], color='violet')        if 'INJ' in self.mapping:            ax4_2 = ax4.twinx()            ax4_2.plot(x_axis, self.df[self.mapping['INJ']], color='lightblue')        ax4.set_title("Смесь AFR (Фиол) и Впрыск мс (Син)", pad=2, fontsize=10)        # 5. Скорость и РХХ        ax5 = fig.add_subplot(gs[4], sharex=ax1)        if 'SPEED' in self.mapping: ax5.plot(x_axis, self.df[self.mapping['SPEED']], color='dodgerblue')        if 'IAC' in self.mapping:            ax5_2 = ax5.twinx()            ax5_2.plot(x_axis, self.df[self.mapping['IAC']], color='white')        ax5.set_title("Скорость (Син) и Шаги РХХ (Бел)", pad=2, fontsize=10)        # 6. Температуры        ax6 = fig.add_subplot(gs[5], sharex=ax1)        if 'T_WATER' in self.mapping: ax6.plot(x_axis, self.df[self.mapping['T_WATER']], color='magenta')        if 'T_AIR' in self.mapping:            ax6_2 = ax6.twinx()            ax6_2.plot(x_axis, self.df[self.mapping['T_AIR']], color='pink')        ax6.set_title("Температуры: ОЖ (Маг) и Впуск (Роз)", pad=2, fontsize=10)        axes_list =[ax1, ax2, ax3, ax4, ax5, ax6]        for ax in axes_list: ax.grid(True, alpha=0.2)        fig.subplots_adjust(left=0.05, right=0.95, top=0.95, bottom=0.05)        canvas = FigureCanvasTkAgg(fig, master=self.plot_frame)        canvas.draw()        canvas.get_tk_widget().pack(side=tk.TOP, fill=tk.BOTH, expand=True)                toolbar = NavigationToolbar2Tk(canvas, self.plot_frame)        toolbar.update()        self.multi = MultiCursor(fig.canvas, axes_list, color='white', lw=1, horizOn=False, vertOn=True, useblit=True)        self.last_idx = -1        fig.canvas.mpl_connect('motion_notify_event', self.on_mouse_move)    def on_mouse_move(self, event):        if not event.inaxes or event.xdata is None: return                idx = np.searchsorted(self.x_values_np, event.xdata)        if idx >= len(self.x_values_np): idx = len(self.x_values_np) - 1                # Обновляем виджеты Tkinter. Это моментально и без лагов!        if idx != self.last_idx:            self.last_idx = idx                        def update_val(key, map_key, is_hp=False, fmt="{:.1f}"):                if is_hp:                    val = self.df.at[self.df.index[idx], 'Calculated_HP']                else:                    col = self.mapping.get(map_key)                    val = self.df.at[self.df.index[idx], col] if col and col in self.df.columns else np.nan                self.text_vars[key].set(fmt.format(val) if pd.notna(val) else "-")            update_val("TIME", "TIME")            update_val("RPM", "RPM", fmt="{:.0f}")            update_val("SPEED", "SPEED", fmt="{:.0f}")            update_val("TPS", "TPS")            update_val("AFR", "AFR", fmt="{:.2f}")            update_val("INJ", "INJ", fmt="{:.2f}")            update_val("GBC", "GBC", fmt="{:.0f}")            update_val("HP", "Calculated_HP", is_hp=True)            update_val("UOS", "UOS")            update_val("KNOCK", "KNOCK")            update_val("IAC", "IAC", fmt="{:.0f}")            update_val("T_WATER", "T_WATER", fmt="{:.0f}")            update_val("T_AIR", "T_AIR", fmt="{:.0f}")    def show_dyno_graph(self):        if self.df is None or not self.mapping: return                rpm, hp = get_dyno_data(self.df, self.mapping)        if rpm is None or rpm.empty:            messagebox.showinfo("Dyno", "Не найдено данных с нажатой педалью газа (Дроссель > 80%).")            return        dyno_window = tk.Toplevel(self.root)        dyno_window.title("Dyno График: Мощность / Обороты (WOT)")        dyno_window.geometry("800x600")                fig = plt.figure(figsize=(8, 6))        ax = fig.add_subplot(111)        ax.plot(rpm, hp, color='lime', linewidth=3, label='Расчетная мощность')        ax.set_xlabel("Обороты двигателя (RPM)", fontsize=12)        ax.set_ylabel("Мощность (л.с.)", fontsize=12)        ax.set_title("Замер Мощности при полностью открытом дросселе", fontsize=14)        ax.grid(True, alpha=0.3)        ax.legend()                canvas = FigureCanvasTkAgg(fig, master=dyno_window)        canvas.draw()        canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)        NavigationToolbar2Tk(canvas, dyno_window).update()if __name__ == "__main__":    root = tk.Tk()    app = LogAnalyzerApp(root)    root.mainloop()